struct Quote: Identifiable, Codable, Hashable {
    var id: String { symbol }
    let symbol: String
    let name: String
    let price: Double
    let change: Double
    let changePercent: Double
}

struct Position: Identifiable, Codable {
    var id: String { symbol }
    let symbol: String
    var quantity: Double
    var averageCost: Double
    var marketPrice: Double

    var marketValue: Double { quantity * marketPrice }
    var unrealizedPnL: Double { (marketPrice - averageCost) * quantity }
}

struct Portfolio: Codable {
    var cash: Double
    var buyingPower: Double
    var dailyPnL: Double
    var positions: [Position]

    var totalValue: Double {
        cash + positions.reduce(0) { $0 + $1.marketValue }
    }

    func position(for symbol: String) -> Position? {
        positions.first(where: { $0.symbol == symbol })
    }

    static let mock = Portfolio(
        cash: 125000,
        buyingPower: 250000,
        dailyPnL: 1840.22,
        positions: [
            Position(symbol: "AAPL", quantity: 150, averageCost: 178.20, marketPrice: 182.44),
            Position(symbol: "TSLA", quantity: 40, averageCost: 221.10, marketPrice: 229.80),
            Position(symbol: "MSFT", quantity: 75, averageCost: 401.30, marketPrice: 412.55)
        ]
    )
}

enum OrderSide: String, Codable, CaseIterable {
    case buy
    case sell
}

enum OrderType: String, Codable, CaseIterable {
    case market
    case limit
}

enum OrderStatus: String, Codable {
    case pending
    case filled
    case rejected

    var color: Color {
        switch self {
        case .pending: return .yellow
        case .filled: return .green
        case .rejected: return .red
        }
    }
}

struct OrderRequest: Codable {
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Double
    let limitPrice: Double?
}

struct Order: Identifiable, Codable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Double
    let limitPrice: Double?
    let executedPrice: Double
    let status: OrderStatus
    let createdAt: Date
}

final class MarketDataService: ObservableObject {
    @Published var quotes: [Quote] = []
    private var timer: AnyCancellable?

    func connect(symbols: [String]) {
        let base: [String: (String, Double)] = [
            "AAPL": ("Apple", 182.44),
            "TSLA": ("Tesla", 229.80),
            "MSFT": ("Microsoft", 412.55),
            "NVDA": ("NVIDIA", 903.20),
            "AMZN": ("Amazon", 180.12)
        ]

        quotes = symbols.compactMap { symbol in
            guard let item = base[symbol] else { return nil }
            return Quote(symbol: symbol, name: item.0, price: item.1, change: 0, changePercent: 0)
        }

        timer?.cancel()
        timer = Timer.publish(every: 1.2, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.tick()
            }
    }

    private func tick() {
        quotes = quotes.map { quote in
            let delta = Double.random(in: -1.8...1.8)
            let newPrice = max(1, quote.price + delta)
            let change = newPrice - quote.price
            let pct = (change / quote.price) * 100
            return Quote(
                symbol: quote.symbol,
                name: quote.name,
                price: newPrice,
                change: change,
                changePercent: pct
            )
        }
    }
}

final class PortfolioService: ObservableObject {
    @Published var portfolio: Portfolio = .mock

    func loadInitialPortfolio() {
        portfolio = .mock
    }

    func apply(order: Order) {
        var portfolio = self.portfolio
        let cost = order.executedPrice * order.quantity

        switch order.side {
        case .buy:
            guard portfolio.cash >= cost else { return }
            portfolio.cash -= cost
            portfolio.buyingPower = max(0, portfolio.buyingPower - cost * 2)
            if let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) {
                let existing = portfolio.positions[index]
                let newQty = existing.quantity + order.quantity
                let newAvg = ((existing.averageCost * existing.quantity) + cost) / newQty
                portfolio.positions[index].quantity = newQty
                portfolio.positions[index].averageCost = newAvg
                portfolio.positions[index].marketPrice = order.executedPrice
            } else {
                portfolio.positions.append(
                    Position(symbol: order.symbol, quantity: order.quantity, averageCost: order.executedPrice, marketPrice: order.executedPrice)
                )
            }
        case .sell:
            guard let index = portfolio.positions.firstIndex(where: { $0.symbol == order.symbol }) else { return }
            guard portfolio.positions[index].quantity >= order.quantity else { return }
            portfolio.positions[index].quantity -= order.quantity
            portfolio.positions[index].marketPrice = order.executedPrice
            portfolio.cash += cost
            portfolio.buyingPower += cost * 2
            if portfolio.positions[index].quantity == 0 {
                portfolio.positions.remove(at: index)
            }
        }

        portfolio.dailyPnL += Double.random(in: -250...450)
        self.portfolio = portfolio
    }
}

final class TradeService: ObservableObject {
    @Published var orders: [Order] = []
    @Published var alerts: [String] = []

    private var api: APIClient?
    private var portfolioService: PortfolioService?
    private var session: Session?

    func configure(api: APIClient, portfolioService: PortfolioService, session: Session?) {
        self.api = api
        self.portfolioService = portfolioService
        self.session = session
    }

    func submit(order request: OrderRequest) {
        guard let api = api, let portfolioService = portfolioService, let session = session else { return }
        guard request.quantity > 0 else {
            alerts.append("Invalid quantity for \(request.symbol)")
            return
        }

        let executionPrice = request.type == .market
            ? simulatedMarketPrice(for: request.symbol)
            : (request.limitPrice ?? simulatedMarketPrice(for: request.symbol))

        let pending = Order(
            id: UUID().uuidString,
            symbol: request.symbol,
            side: request.side,
            type: request.type,
            quantity: request.quantity,
            limitPrice: request.limitPrice,
            executedPrice: executionPrice,
            status: .pending,
            createdAt: Date()
        )

        orders.append(pending)
        alerts.append("Order submitted: \(request.side.rawValue.uppercased()) \(Int(request.quantity)) \(request.symbol)")

        Task {
            do {
                let signed = try api.executeTrade(request: request, session: session)
                try await Task.sleep(nanoseconds: 700_000_000)

                let finalStatus: OrderStatus = signed.accepted ? .filled : .rejected
                let finalOrder = Order(
                    id: pending.id,
                    symbol: pending.symbol,
                    side: pending.side,
                    type: pending.type,
                    quantity: pending.quantity,
                    limitPrice: pending.limitPrice,
                    executedPrice: pending.executedPrice,
                    status: finalStatus,
                    createdAt: pending.createdAt
                )

                await MainActor.run {
                    if let idx = self.orders.firstIndex(where: { $0.id == pending.id }) {
                        self.orders[idx] = finalOrder
                    }
                    if finalStatus == .filled {
                        portfolioService.apply(order: finalOrder)
                        self.alerts.append("Filled \(finalOrder.side.rawValue.uppercased()) \(Int(finalOrder.quantity)) \(finalOrder.symbol) @ \(finalOrder.executedPrice.currencyString)")
                    } else {
                        self.alerts.append("Order rejected for \(finalOrder.symbol)")
                    }
                }
            } catch {
                await MainActor.run {
                    if let idx = self.orders.firstIndex(where: { $0.id == pending.id }) {
                        self.orders[idx] = Order(
                            id: pending.id,
                            symbol: pending.symbol,
                            side: pending.side,
                            type: pending.type,
                            quantity: pending.quantity,
                            limitPrice: pending.limitPrice,
                            executedPrice: pending.executedPrice,
                            status: .rejected,
                            createdAt: pending.createdAt
                        )
                    }
                    self.alerts.append("Secure transmission failed for \(request.symbol)")
                }
            }
        }
    }

    private func simulatedMarketPrice(for symbol: String) -> Double {
        switch symbol {
        case "AAPL": return 182.44 + Double.random(in: -0.8...0.8)
        case "TSLA": return 229.80 + Double.random(in: -1.5...1.5)
        case "MSFT": return 412.55 + Double.random(in: -1.2...1.2)
        case "NVDA": return 903.20 + Double.random(in: -3.5...3.5)
        case "AMZN": return 180.12 + Double.random(in: -0.9...0.9)
        default: return 100 + Double.random(in: -2...2)
        }
    }
}

struct SignedTradeResponse {
    let accepted: Bool
    let requestId: String
}

final class APIClient {
    private let baseURL = URL(string: "https://api.investment-platform.local")!
    private let encoder = JSONEncoder()

    func executeTrade(request: OrderRequest, session: Session) throws -> SignedTradeResponse {
        let body = try encoder.encode(request)
        let signature = HMACSigner.shared.sign(data: body, secret: session.token)
        var urlRequest = URLRequest(url: baseURL.appendingPathComponent("/v1/trades/execute"))
        urlRequest.httpMethod = "POST"
        urlRequest.httpBody = body
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.setValue("Bearer \(session.token)", forHTTPHeaderField: "Authorization")
        urlRequest.setValue(signature, forHTTPHeaderField: "X-Signature")
        urlRequest.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-Id")
        _ = urlRequest
        return SignedTradeResponse(accepted: Bool.random(probability: 0.92), requestId: UUID().uuidString)
    }
}

final class HMACSigner {
    static let shared = HMACSigner()

    func sign(data: Data, secret: String) -> String {
        let key = SymmetricKey(data: Data(secret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(signature).base64EncodedString()
    }
}

final class KeychainService {
    static let shared = KeychainService()

    func save(_ value: String, key: String) {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }

    func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess,
              let data = item as? Data,
              let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        return value
    }
}

extension Double {
    var currencyString: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }
}

extension Bool {
    static func random(probability: Double) -> Bool {
        Double.random(in: 0...1) <= probability
    }
}